{
var seed = GetInt(parameters, "seed", context.Seed);
    var count = Math.Max(1, GetInt(parameters, "count", 8));
    var radius = Math.Clamp(GetFloat(parameters, "radius", 0.35f), 0f, 1f);
    var rings = Math.Max(1, GetInt(parameters, "rings", 1));
    var spotSize = Math.Clamp(GetFloat(parameters, "spotSize", 0.10f), 0.001f, 1f);
    var shapeType = GetChoice(parameters, "shapeType", "sphere");
    var sizeVariation = GetFloat(parameters, "sizeVariation", 0.3f);
    var rotationVariation = GetFloat(parameters, "rotationVariation", 0f);
    var startAngle = GetFloat(parameters, "startAngle", 0f) * MathF.PI / 180f;
    var softness = Math.Max(0f, GetFloat(parameters, "softness", 0.25f));
    var colorA = GetColor(parameters, "colorA", Color.FromRgb(230,230,230));
    var colorB = GetColor(parameters, "colorB", Color.FromRgb(0,0,0));
    var invert = GetBool(parameters, "invert", false);

    var shapeInput = inputs.Length > 0 ? inputs[0] : null;
    var bgInput = inputs.Length > 1 ? inputs[1] : null;

    var size = context.TileSize;
    var buffer = new PixelBuffer(size, size);

    // center in pixel coordinates
    var cx = size * 0.5f;
    var cy = size * 0.5f;

    // radius in pixels (relative to half tile)
    var radiusPx = radius * (size * 0.5f);

    // spot radius in pixels (roughly the visual radius)
    var spotRadiusPx = Math.Max(1f, spotSize * size);

    // base softness
    var baseSoftness = Math.Max(0.001f, softness);

    // Pre-compute shape flags outside the loop
    var isRingShape = shapeType == "ring";

    buffer.ParallelForEachPixel((x, y) =>
    {
        var px = x + 0.5f;
        var py = y + 0.5f;

        float best = 0f;

        // Multiple concentric rings support: iterate rings and spots per ring
        for (int r = 0; r < rings; r++)
        {
            // compute ring radius as fraction of base radius; distribute between 0.4..1.0
            float ringRadiusFactor = rings == 1 ? 1f : (0.4f + r * (0.6f / Math.Max(1, rings - 1)));
            var ringRadiusPx = radiusPx * ringRadiusFactor;

            // per-ring spot size with random variation per spot
            for (int i = 0; i < count; i++)
            {
                // Per-spot random size modifier
                var sizeMod = 1f - sizeVariation * 0.5f + HashToUnit(i, r + 100, seed + 50) * sizeVariation;
                var ringSpotRadius = spotRadiusPx * (1f - r * 0.08f) * Math.Max(0.1f, sizeMod);
                var sigmaRing = Math.Max(0.5f, ringSpotRadius * baseSoftness);
                var invTwoSigmaSqRing = 1f / (2f * sigmaRing * sigmaRing);

                // Angular position with optional rotation variation
                var angleOffset = HashToUnit(i, r, seed) * rotationVariation * MathF.Tau;
                var angle = startAngle + (i / (float)count) * MathF.Tau + angleOffset;
                // slight per-spot radial jitter (deterministic) to avoid perfect repetition
                var rOffset = (HashToUnit(i, r, 0) - 0.5f) * (ringSpotRadius * 0.12f);
                var spotCx = cx + (ringRadiusPx + rOffset) * MathF.Cos(angle);
                var spotCy = cy + (ringRadiusPx + rOffset) * MathF.Sin(angle);

                var dx = px - spotCx;
                var dy = py - spotCy;

                float contrib;
                // If user explicitly selected custom and provided a shape input, use it.
                if (shapeType == "custom" && shapeInput is not null)
                {
                    contrib = SampleShapeFromBuffer(shapeInput, dx, dy, ringSpotRadius);
                }
                else
                {
                    // fallback to builtin shapes — pass rotation variation if applicable
                    var spotAngle = rotationVariation > 0f ? angle : 0f;
                    contrib = BuiltinShapeSample(shapeType, isRingShape, dx, dy, ringSpotRadius, invTwoSigmaSqRing, spotAngle);
                }

                if (contrib > best) best = contrib;
            }
        }

        best = Math.Clamp(best, 0f, 1f);
        if (invert) best = 1f - best;

        // blend between background (B) and foreground (A)
        var aR = colorA.R / 255f;
        var aG = colorA.G / 255f;
        var aB = colorA.B / 255f;

        float bR, bG, bB;
        if (bgInput is not null)
        {
            // map output pixel coords into background buffer space (scale if needed)
            var bx = (int)MathF.Round(x * (bgInput.Width / (float)size));
            var by = (int)MathF.Round(y * (bgInput.Height / (float)size));
            var bp = bgInput.GetPixelWrapped(bx, by);
            bR = bp.R;
            bG = bp.G;
            bB = bp.B;
        }
        else
        {
            bR = colorB.R / 255f;
            bG = colorB.G / 255f;
            bB = colorB.B / 255f;
        }

        var outR = bR * (1f - best) + aR * best;
        var outG = bG * (1f - best) + aG * best;
        var outB = bB * (1f - best) + aB * best;

        buffer.SetPixel(x, y, outR, outG, outB, 1f);
    });

    return buffer;

private static float SampleShapeFromBuffer(PixelBuffer buf, float dx, float dy, float ringSpotRadius)
{
    if (buf is null) return 0f;
    var w = buf.Width;
    var h = buf.Height;
    if (w <= 0 || h <= 0) return 0f;

    // Map local coordinates into shape buffer space. We assume the shape image covers diameter = 2 * ringSpotRadius.
    // Center of the spot maps to texture UV (0.5,0.5). Values outside [0,1] are treated as zero
    // (no contribution) so the shape does not tile.
    var nx = (dx / (ringSpotRadius * 2f)) + 0.5f; // 0..1
    var ny = (dy / (ringSpotRadius * 2f)) + 0.5f;

    if (nx < 0f || nx > 1f || ny < 0f || ny > 1f)
        return 0f;

    var ix = (int)MathF.Round(nx * (w - 1));
    var iy = (int)MathF.Round(ny * (h - 1));

    // Nearest sampling without wrapping so shape image is used as a single silhouette.
    var val = buf.GetValue(ix, iy);
    return Math.Clamp(val, 0f, 1f);
}

private static float BuiltinShapeSample(string shapeType, bool isRing, float dx, float dy, float ringSpotRadius, float invTwoSigmaSq, float rotation)
{
    // Apply rotation to coordinates for non-circular shapes
    var cosR = MathF.Cos(rotation);
    var sinR = MathF.Sin(rotation);
    var rdx = dx * cosR - dy * sinR;
    var rdy = dx * sinR + dy * cosR;

    // normalized radial distance
    var r = MathF.Sqrt(dx * dx + dy * dy);

    if (isRing)
    {
        // Ring shape: a circular outline with thickness
        var ringThickness = ringSpotRadius * 0.3f;
        var ringCenter = ringSpotRadius * 0.7f;
        var distToRing = MathF.Abs(r - ringCenter);
        var ringVal = 1f - distToRing / ringThickness;
        return SmoothStep(0f, 1f, Math.Clamp(ringVal, 0f, 1f));
    }

    switch (shapeType)
    {
        case "square":
            var d = MathF.Max(MathF.Abs(rdx), MathF.Abs(rdy));
            var nx = d / ringSpotRadius; // 0=center..1=edge
            return SmoothStep(0f, 1f, Math.Clamp(1f - nx, 0f, 1f));
        case "diamond":
            var l1 = (MathF.Abs(rdx) + MathF.Abs(rdy)) / ringSpotRadius;
            return SmoothStep(0f, 1f, Math.Clamp(1f - l1, 0f, 1f));
        case "star":
            // radial stars: use angular modulation to create points
            var angle = MathF.Atan2(rdy, rdx);
            var spikes = MathF.Abs(MathF.Cos(angle * 5f)); // 5-point star
            var radial = r / ringSpotRadius;
            var profile = 1f - radial * (0.6f + 0.4f * spikes);
            return SmoothStep(0f, 1f, Math.Clamp(profile, 0f, 1f));
        default:
            // sphere: use gaussian for soft round blob (matches previous behavior)
            return MathF.Exp(-(r * r) * invTwoSigmaSq);
    }
    }
}
